    const body = await req.json();
    const { userId } = body;

    if (!userId) {
      return { success: false, error: '缺少用户ID' };
    }

    return freezeService.unfreezeAccount(userId);
  }

  /**
   * 查询冻结状态
   * GET /api/freeze/status/:userId
   */
  async getFreezeStatus(req: Request): Promise<ApiResponse> {
    const url = new URL(req.url);
    const userId = url.pathname.split('/').pop();

    if (!userId) {
      return { success: false, error: '缺少用户ID' };
    }

    return freezeService.getFreezeStatus(userId);
  }

  /**
   * 查询冻结记录
   * GET /api/freeze/records/:userId
   */
  async getFreezeRecords(req: Request): Promise<ApiResponse> {
    const url = new URL(req.url);
    const userId = url.pathname.split('/').pop();

    if (!userId) {
      return { success: false, error: '缺少用户ID' };
    }

    return freezeService.getFreezeRecords(userId);
  }
}

